String s = "2147483647"; // 正好是 MAX_VALUE
int result = 0;
for(char c : s.toCharArray()){
    int digit = c - '0';
    // 检查溢出
    if(result > Integer.MAX_VALUE / 10 || (result == Integer.MAX_VALUE / 10 && digit > 7)){
        System.out.println("溢出");
        break;
    }
    result = result * 10 + digit;
}
System.out.println(result);

